class MarketSocket {
  constructor() {
    this.socket = null;
    this.listeners = new Set();
    this.url = process.env.REACT_APP_WS_URL || "ws://localhost:8000/ws/pulse";
    this.reconnectTimeout = null;
    this.heartbeatInterval = null;
  }

  /**
   * Initializes the connection with the JWT token for identity verification.
   */
  connect() {
    const token = localStorage.getItem('token');
    
    // 1. Prevent duplicate connections or connecting without an identity
    if (this.socket?.readyState === WebSocket.OPEN) return;
    if (!token) {
      console.warn("SOCKET_DENIED: No identity token found.");
      return;
    }

    // 2. Pass token via query param (Standard for WebSockets since they don't support custom headers)
    const authenticatedUrl = `${this.url}?token=${token}`;
    this.socket = new WebSocket(authenticatedUrl);

    this.socket.onopen = () => {
      console.log("✅ MARKET_PULSE_ESTABLISHED");
      this.startHeartbeat();
    };

    this.socket.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        // Dispatch data to all registered React component listeners
        this.listeners.forEach((callback) => callback(data));
      } catch (err) {
        console.error("PULSE_PARSE_ERROR:", err);
      }
    };

    this.socket.onclose = (event) => {
      this.stopHeartbeat();
      if (event.code !== 1000) { // 1000 = Normal Closure
        console.warn("⚠️ MARKET_PULSE_OFFLINE. Retrying...");
        this.reconnect();
      }
    };

    this.socket.onerror = (err) => {
      console.error("SOCKET_CRITICAL_FAILURE:", err);
      this.socket.close();
    };
  }

  reconnect() {
    if (this.reconnectTimeout) return;
    this.reconnectTimeout = setTimeout(() => {
      this.reconnectTimeout = null;
      this.connect();
    }, 5000);
  }

  startHeartbeat() {
    this.heartbeatInterval = setInterval(() => {
      if (this.socket?.readyState === WebSocket.OPEN) {
        this.socket.send(JSON.stringify({ type: "ping" }));
      }
    }, 30000); // 30 second pulse
  }

  stopHeartbeat() {
    clearInterval(this.heartbeatInterval);
  }

  subscribe(tickers) {
    if (this.socket?.readyState === WebSocket.OPEN) {
      this.socket.send(JSON.stringify({ action: "subscribe", tickers }));
    } else {
      console.error("SUBSCRIBE_FAILED: Socket not ready.");
    }
  }

  addListener(callback) {
    this.listeners.add(callback);
    // Returns cleanup function for useEffect
    return () => this.listeners.delete(callback);
  }

  disconnect() {
    this.stopHeartbeat();
    if (this.socket) {
      this.socket.close(1000, "User logout");
      this.socket = null;
    }
  }
}

const marketSocket = new MarketSocket();
export default marketSocket;
